head.script:
//전역변수
scwin.login = "";
scwin.strCurDate = "";
scwin.acctYear = "";

//조회, 수정 구별하기 위한 변수
scwin.load_row = "";  //조회후 focus가게 할  row
scwin.currentRowPosition = 0;
scwin.vCoCd = "";
scwin.vCoClsCd = "";

//히든 컴포넌트
scwin.hd_txtCoCd = "";
scwin.hd_txtCoClsCd = "";
scwin.hd_txt_countRow = "";

//코드 컴포넌트 구분
scwin.codeComp = "";

//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    scwin.login = $c.data.getMemInfo();
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    scwin.acctYear = $c.date.getServerDateTime("yyyy");

    scwin.currentRowPosition = -1;
    scwin.vCoCd = scwin.login.coCd || ""; // 소속 자회사  
    scwin.vCoClsCd = scwin.login.coClsCd || "";//회계_회사구분('CO035' : 0:동부 EXPRESS)

    const codeOptions = [
        { grpCd: "CO016", compID: "lc_comCostClsCd" }, // 공통비구분
        { grpCd: "CO026", compID: "lc_acctDeptLvl" }, // 귀속부서레벨
        { grpCd: "FI042", compID: "lc_costClsCd" },
        { grpCd: "FI089", compID: "lc_bizTaxAggrPatternCd" },
        { grpCd: "CO035", compID: "lc_coClsCd" } //자회사구분
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = function () {
    lc_comCostClsCd.setValue("");
    lc_acctDeptLvl.setValue("");
    lc_costClsCd.setValue("");
    lc_bizTaxAggrPatternCd.setValue("");
    lc_coClsCd.setValue("");
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
    $c.gus.cfDisableKeyData();
    scwin.f_ToggleImgBtn(false);

    scwin.f_ResetBizdom();

    setTimeout(async function () {
        await scwin.srchBizdivSetting();
        lc_srchUseYn.setValue(1);
        ica_search_acctYear.setValue(scwin.acctYear);

        if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {
            scwin.hd_txtCoCd = scwin.vCoCd
            scwin.hd_txtCoClsCd = scwin.vCoClsCd;
        }
    }, 100)


    $c.gus.cfDisableObjects(tb_dept);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    debugger
    scwin.currentRowPosition = -1;
    //ds_search.UseChangeInfo = false;

    //dataSetDebug(ds_search, true);
    //조회조건
    var json = {
        "acctYear": ica_search_acctYear.getValue(),
        "acctDeptCd": ed_sacctDeptCd.getValue(),
        "useYn": lc_srchUseYn.getValue(),
        "coCd": scwin.hd_txtCoCd,
        "coClsCd": scwin.hd_txtCoClsCd
    };
    ds_search.removeAll();
    ds_search.setRowJSON(0, json);

    // if (!await $c.gus.cfValidate([sbm_search])) {
    //     return;
    // }

    $c.sbm.execute(sbm_search);
};

//-------------------------------------------------------------------------
// 현재 년도 트리를 다음 년도 트리로 생성
//-------------------------------------------------------------------------	
scwin.f_createNextYearTree = async function (e) {
    if (await $c.win.confirm(MSG_CM_CRM_001)) {
        scwin.load_row = ds_search.getCellData(0, "acctYear");

        //조회조건
        var json = {
            "acctYear": ica_search_acctYear.getValue(),
            "acctDeptCd": ed_sacctDeptCd.getValue(),
            "useYn": lc_srchUseYn.getValue(),
            "coCd": scwin.hd_txtCoCd,
            "coClsCd": scwin.hd_txtCoClsCd
        };
        ds_search.removeAll();
        ds_search.setRowJSON(0, json);

        $c.sbm.execute(sbm_saveNextYear);

        // disable 처리
        $c.gus.cfDisableKeyData();
    }
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_PopUp = function (paramArray) {
    var codeObj = paramArray.pCode;
    var nameObj = paramArray.pName;
    var udcObj = paramArray.udcComp

    udcObj.setSelectId(paramArray.pSelectID);
    udcObj.cfCommonPopUp(function (rtnList) {
        if (rtnList != null) {
            if (rtnList[0] != "N/A") {
                $c.gus.cfSetValue(codeObj, rtnList[0]);
                codeObj.options.hidVal = rtnList[0];
                $c.gus.cfSetValue(nameObj, rtnList[1]);
            }
        } else {
            $c.gus.cfSetValue(codeObj, "");
            codeObj.options.hidVal = "";
            $c.gus.cfSetValue(nameObj, "");
        }

        return rtnList;
    }, $c.gus.cfGetValue(codeObj), ""
        //, f_EventCheck(), paramArray.pDispCnt
        , paramArray.check, paramArray.pDispCnt
        , paramArray.pTitle, paramArray.pWidth
        , paramArray.pHidden, paramArray.pWhere
        , paramArray.pW, paramArray.pH
        , paramArray.pTop, paramArray.pLeft
        , paramArray.pExistTF, paramArray.pAllSearchTF
        , paramArray.pWtitleSearch)
};

//-------------------------------------------------------------------------
// 팝업 여부 검사
//-------------------------------------------------------------------------
scwin.f_IsPopUp = function (inObj) {
    var inValue = $c.gus.cfGetValue(inObj);
    var hidValue = inObj.options.hidVal;

    if ($c.gus.cfIsNull(inValue)) {
        inObj.options.hidVal = "";
        for (var i = 0; i < scwin.f_IsPopUp.arguments.length; i++) {
            $c.gus.cfSetValue(scwin.f_IsPopUp.arguments[i], "");
        }
        return false;
    }
    if (inValue == hidValue) return false;

    return true;
};

//-------------------------------------------------------------------------
// 팝업 이벤트에 따라 팝업창의 자동닫기 여부를 반환
//-------------------------------------------------------------------------
// scwin.f_EventCheck = function() {
//     if (window.event != null && window.event.srcElement.tagName.toUpperCase() == "IMG") {
//         return 'F';
