//-------------------------------------------------------------------------
// 조회 귀속부서코드팝업
//-------------------------------------------------------------------------
scwin.f_deptPopUp = function (check) {
    var param = scwin.strCurDate;

    if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템
        param = param + "," + scwin.vCoCd + "," + scwin.vCoClsCd;
    }

    var paramArray = {};
    paramArray.pSelectID = "retrieveAcctDeptCdInfo6";
    paramArray.pCode = ed_sacctDeptCd;
    paramArray.pName = ed_sacctDeptNm;
    paramArray.pWhere = param;
    paramArray.udcComp = udc_sacctDept;
    paramArray.check = check

    scwin.f_PopUp(paramArray);
};

//-------------------------------------------------------------------------
// 상위귀속부서코드팝업
//-------------------------------------------------------------------------
scwin.f_upperAcctCdPopUp = function () {
    var param = ds_dept.getCellData(ds_dept.getRowPosition(), "acctDeptCd");

    if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템
        param = param + ",,,," + scwin.vCoCd + "," + scwin.vCoClsCd;
    }

    var paramArray = {};
    paramArray.pSelectID = "retrieveAcctDeptCdInfo2";
    paramArray.pCode = ed_upperAcctDeptCd;
    paramArray.pName = ed_upperAcctDeptNm;
    paramArray.pWhere = param;
    paramArray.udcComp = udc_upperAcctDept;

    scwin.f_PopUp(paramArray);
};

