scwin.f_assetsCdPopUp = function () {
    var param = "";
    if (scwin.vCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  	// 자회사 회계 시스템
        param = param + "," + vCoCd + "," + vCoClsCd + ",0";
    }

    var paramArray = {};
    paramArray.pSelectID = "retrieveAcctDeptCdInfo6";
    paramArray.pCode = ed_asetAcctDeptCd;
    paramArray.pName = txt_asetAcctDeptNm;
    paramArray.pWhere = param;
    paramArray.udcComp = udc_asetAcctDept;

    scwin.f_PopUp(paramArray);
};

//-------------------------------------------------------------------------
// 지사/집계부서코드 팝업
//-------------------------------------------------------------------------
scwin.f_branchAggrDeptCdPopUp = async function () {
    await udc_branchAggrDept.cfCommonPopUp(async function (rtnList) {
        if (!$c.gus.cfIsNull(rtnList)) {
            if (rtnList[8] != 1) {  //집계부서가 아니면 리턴
                await $c.gus.alert("지사/집계부서는 집계부서인 경우만 선택이 가능합니다.");
                ed_branchAggrDeptCd.setValue("");
                ed_branchAggrDeptNm.setValue("");
                return;
            } else {
                ed_branchAggrDeptCd.setValue(rtnList[0]);
                ed_branchAggrDeptNm.setValue(rtnList[1]);
            }
        } else {
            ed_branchAggrDeptCd.setValue("");
            ed_branchAggrDeptNm.setValue("");
        }
    }, ed_branchAggrDeptCd.getValue(), "", "T", null, null, null, null, null, null, null, null, null);
};

//-------------------------------------------------------------------------
// 팝업
//-------------------------------------------------------------------------
scwin.f_CallCommonPopUp = function (paramArray) {
    if (cfIsNull(paramArray.pCode)) paramArray.pCode = "";
    if (cfIsNull(paramArray.pName)) paramArray.pName = "";

    var udcObj = paramArray.udcComp
    udcObj.setSelectId(paramArray.pSelectID);

    udcObj.cfCommonPopUp(function (rtnList) {
        if ($c.gus.cfIsNull(rtnList)) {
            $c.gus.cfSetValue(codeObj, "");
            $c.gus.cfSetValue(nameObj, "");
            $c.gus.cfSetHiddenValue(codeObj, "");
            $c.gus.cfSetHiddenValue(nameObj, "");
        } else if (rtnList[0] == "N/A") {
            $c.gus.cfSetValue(codeObj, $c.gus.cfGetHiddenValue(codeObj));
            $c.gus.cfSetValue(nameObj, $c.gus.cfGetHiddenValue(nameObj));
        } else {
            $c.gus.cfSetValue(codeObj, rtnList[2]);
            $c.gus.cfSetValue(nameObj, rtnList[3]);
            $c.gus.cfSetHiddenValue(codeObj, rtnList[2]);
            $c.gus.cfSetHiddenValue(nameObj, rtnList[3]);
        }
    }, paramArray.pCode, paramArray.pName
        , paramArray.pWinCloseTF, paramArray.pDispCnt
        , paramArray.pTitle, paramArray.pWidth
        , paramArray.pHidden, paramArray.pWhere
        , paramArray.pW, paramArray.pH
        , paramArray.pTop, paramArray.pLeft
        , paramArray.pExistTF, paramArray.pAllSearchTF
        , paramArray.pWtitleSearch)
};

