//-------------------------------------------------------------------------
// 부가세귀속부서팝업
//-------------------------------------------------------------------------
scwin.f_VatDeclarAcctDeptCd = function () {
    var codeObj = ed_vatDeclarAcctDeptCd;
    var nameObj = ed_vatDeclarAcctDeptNm;

    var paramArray = {};
    paramArray.pSelectID = "retrieveVatDeclarAcctDeptCd";
    paramArray.pCode = $c.gus.cfGetValue(codeObj);
    paramArray.pName = $c.gus.cfGetValue(nameObj);
    paramArray.pWinCloseTF = "F" //scwin.f_EventCheck();
    paramArray.pAllSearchTF = 'T'
    paramArray.pWhere = ",,1,,"
    paramArray.pW = "410"

    if (paramArray.pWinCloseTF == 'T' && $c.gus.cfCanOpenPopup(codeObj, nameObj) == false) {
        return;
    }
    scwin.f_CallCommonPopUp(paramArray);
};

//-------------------------------------------------------------------------
// 구청팝업
