scwin.f_dOfficeCdPopUp = function () {
    var paramArray = {};
    paramArray.pSelectID = "retrieveDOfficeCdInfo";
    paramArray.pCode = ed_withholdDofficeCd;
    paramArray.pName = ed_withholdDofficeNm;
    paramArray.pWhere = "1";
    paramArray.udcComp = udc_withholdDoffice;

    scwin.f_PopUp(paramArray);
};


//-------------------------------------------------------------------------
// 코드검증 Hidden 값 설정
//-------------------------------------------------------------------------
scwin.f_SetHidVal = function () {
    var row = ds_dept.getRowPosition();

    ed_upperAcctDeptCd.options.hidVal = ds_dept.getCellData(row, "upperAcctDeptCd");
    ed_budgetCntlAcctDeptCd.options.hidVal = ds_dept.getCellData(row, "budgetCntlAcctDeptCd");
    ed_vatDeclarAcctDeptCd.options.hidVal = ds_dept.getCellData(row, "vatDeclarAcctDeptCd");
    ed_advcdExecAcctDeptCd.options.hidVal = ds_dept.getCellData(row, "advcdExecAcctDeptCd");
    ed_fundExecAcctDeptCd.options.hidVal = ds_dept.getCellData(row, "fundExecAcctDeptCd");
    ed_withholdDofficeCd.options.hidVal = ds_dept.getCellData(row, "withholdDofficeCd");
};

//-------------------------------------------------------------------------
// 이미지 버튼의 Enable/Disable
//-------------------------------------------------------------------------
scwin.f_ToggleImgBtn = function (mode) {
    if (mode == true) {
        // $c.gus.cfEnableObjects([img_upperAcctDept, img_budgetCntlAcctDept
        //     , img_vatDeclarAcctDept, img_advcdExecAcctDept
        //     , img_fundExecAcctDept, img_withholdDoffice
        //     , img_adptStDt, img_adptEndDt, img_asetAcctDeptCd
        //     , img_company, img_acctYear]);

        $c.gus.cfEnableObjects([udc_upperAcctDept, udc_budgetCntlAcctDept
            , udc_vatDeclarAcctDept, udc_advcdExecAcctDept
            , udc_fundExecAcctDept, udc_withholdDoffice
            , udc_fromToCalendar1, udc_asetAcctDept
            , udc_company, ica_acctYear]);
    } else {
        // $c.gus.cfDisableObjects([img_upperAcctDept, img_budgetCntlAcctDept
        //     , img_vatDeclarAcctDept, img_advcdExecAcctDept
        //     , img_fundExecAcctDept, img_withholdDoffice
        //     , img_adptStDt, img_adptEndDt, img_asetAcctDeptCd
        //     , img_company, img_acctYear]);

        $c.gus.cfDisableObjects([udc_upperAcctDept, udc_budgetCntlAcctDept
            , udc_vatDeclarAcctDept, udc_advcdExecAcctDept
            , udc_fundExecAcctDept, udc_withholdDoffice
            , udc_fromToCalendar1, udc_asetAcctDept
            , udc_company, ica_acctYear]);
    }
};

//-------------------------------------------------------------------------
// 사업영역 데이터셋을 Reset
//-------------------------------------------------------------------------
scwin.f_ResetBizdom = async function () {
    sbm_code.action = "/cm.zz.RetrieveCommonPopupCMD.do?"

    var paramV = {
        "sysCd": "CommonEBC",
        "queryId": "retrieveBizDomCdInfo2",
        "param1": "",
        "param2": "",
        "param3": 1
    };

    dma_code.setEmptyValue();
    dma_code.setJSON(paramV);
    scwin.codeComp = "ds_bizdom";

    await $c.sbm.execute(sbm_code);

    // ds_bizdom.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC" +
    //     "&queryId=retrieveBizDomCdInfo2" +
    //     "&param1=&param2=&param3=1";
    // ds_bizdom.Reset();
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//------------------------------------------------------------------------- 
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {
    await udc_company.cfCommonPopUp(function (rtnList) {
        if ($c.gus.cfIsNull(rtnList)) {
            if (rtnList[0] == "N/A") return;

            ed_coCd.setValue(rtnList[0]);	// 코드
            ed_coNm.setValue(rtnList[5]); // 회사명 
            ed_coCd.options.hidVal = rtnList[0];  // 히든값 
            lc_coClsCd.getValue(rtnList[1]);	// 회사구분

            if (rtnList[1] == '0') {
                chb_virtureDeptYn.setValue("N");
                //chb_virtureDeptYn.checked = false;
            } else if (rtnList[1] > '0') {  // 자회사인 경우에만 
                chb_virtureDeptYn.setValue("Y");
                //chb_virtureDeptYn.checked = true;
            }
        } else {
            ed_coCd.setValue("");
            ed_coNm.setValue("");
            ed_coCd.options.hidVal = "";
            chb_virtureDeptYn.setValue("N");
            //chb_virtureDeptYn.checked = false;
        }
    }
        , ed_coCd.getValue()
        , ed_coNm.getValue()
        , pWinCloseTF, null, null, null, null
        , null, null, null, null, null);
    // SET	 
};

scwin.udc_sacctDept_onclickEvent = function (e) {
    scwin.f_deptPopUp("F");
};

scwin.udc_upperAcctDept_onclickEvent = function (e) {
