};

scwin.srchBizdivSetting = async function () {
    sbm_code.action = "/ac.co.stdinfomgnt.RetrieveBusinessDivisionCMD.do?"

    var paramV = {
        "useYn": 1
    };

    dma_code.setEmptyValue();
    dma_code.setJSON(paramV);
    scwin.codeComp = "co_ds_srchBizdiv";

    $c.sbm.execute(sbm_code);
};


scwin.sbm_search_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var rowCnt = ds_dept.getRowCount();
        if (rowCnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }
        $c.gus.cfDisableObjects(tb_dept);
        tv_treeView.findNodeByIndex(1, true);

        // row = ds_dept.NameValueRow("acctDeptCd", load_row);
        // tv_treeView.focus();
        // tv_treeView.index = (row == 0 ? 1 : row);
    };
};


scwin.sbm_saveNextYear_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    };
};

scwin.sbm_code_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        if (scwin.codeComp == "ds_bizdom") {
            ds_bizdom.setJSON(e.responseJSON.GAUCE);
            lc_srchBizdom.setSelectedIndex(-1);

            scwin.codeComp = "";

        } else if (scwin.codeComp = "co_ds_srchBizdiv") {
            co_ds_srchBizdiv.setJSON(e.responseJSON.GAUCE);
            lc_srchBizdiv.setSelectedIndex(-1);
            scwin.codeComp = "";
        }

    };
};

scwin.ds_dept_onrowpositionchange = function (info) {
    var row = info.newRowIndex

    if (row >= 0) {
        scwin.f_SetHidVal();
    }
};

//-------------------------------------------------------------------------
// 귀속부서  validation 
//------------------------------------------------------------------------- 
