//-------------------------------------------------------------------------
// 트리 클릭시
//------------------------------------------------------------------------- 
scwin.tv_treeView_onclick = function () {
    if (scwin.currentRowPosition == ds_dept.getRowPosition()) {
        $c.gus.cfDisableKey();
        scwin.f_ToggleImgBtn(true);
        //$c.gus.cfDisableBtn([bUpdate]);
    } else {
        $c.gus.cfDisableKeyData();
        scwin.f_ToggleImgBtn(false);
        //$c.gus.cfDisableBtn([bSave]);
    }
};
